## 2. `LineAdjustment` (embeddable)

Owned by `ClaimLine`; stored via `@ElementCollection` (no UUID). Use `BigDecimal` with **scale 2, `HALF_UP`** when you set amounts in adjudication.

```java
package com.realfast.claims.model;

import jakarta.persistence.Column;
import jakarta.persistence.Embeddable;
import jakarta.persistence.EnumType;
import jakarta.persistence.Enumerated;
import lombok.AccessLevel;
import lombok.Getter;
import lombok.NoArgsConstructor;
import lombok.Setter;

import java.math.BigDecimal;

@Embeddable
@Getter
@Setter
@NoArgsConstructor(access = AccessLevel.PROTECTED)
public class LineAdjustment {

    @Column(nullable = false, length = 32)
    private String code;

    @Enumerated(EnumType.STRING)
    @Column(nullable = false, length = 20)
    private AdjustmentType type;

    @Column(precision = 19, scale = 2)
    private BigDecimal amount;

    @Column(nullable = false, length = 500)
    private String description;

    public LineAdjustment(String code, AdjustmentType type, BigDecimal amount, String description) {
        this.code = code;
        this.type = type;
        this.amount = amount;
        this.description = description;
    }

    public static LineAdjustment denial(String code, String description) {
        return new LineAdjustment(code, AdjustmentType.DENIAL, BigDecimal.ZERO.setScale(2), description);
    }

    public static LineAdjustment reduction(String code, BigDecimal amount, String description) {
        return new LineAdjustment(code, AdjustmentType.REDUCTION, money(amount), description);
    }

    private static BigDecimal money(BigDecimal value) {
        return value.setScale(2, java.math.RoundingMode.HALF_UP);
    }
}
```

**Why embeddable:** explanations are part of the line, not a separate aggregate.

---

## 3. `ClaimLine` entity

Child of `Claim`. Money: `billedAmount` (required on submit), `approvedAmount` (set at adjudication; `null` while `PENDING`).

```java
package com.realfast.claims.model;

import jakarta.persistence.*;
import lombok.AccessLevel;
import lombok.Getter;
import lombok.NoArgsConstructor;
import lombok.Setter;

import java.math.BigDecimal;
import java.math.RoundingMode;
import java.time.LocalDate;
import java.util.ArrayList;
import java.util.List;
import java.util.UUID;

@Entity
@Table(name = "claim_lines")
@Getter
@Setter
@NoArgsConstructor(access = AccessLevel.PROTECTED)
public class ClaimLine {

    @Id
    @GeneratedValue(strategy = GenerationType.UUID)
    private UUID id;

    @ManyToOne(fetch = FetchType.LAZY, optional = false)
    @JoinColumn(name = "claim_id", nullable = false)
    private Claim claim;

    @Column(nullable = false)
    private int lineNumber;

    @Column(nullable = false, length = 20)
    private String procedureCode;

    @Column(length = 20)
    private String diagnosisCode;

    @Column(nullable = false)
    private LocalDate serviceDate;

    @Column(nullable = false)
    private int units = 1;

    @Column(nullable = false, precision = 19, scale = 2)
    private BigDecimal billedAmount;

    @Column(precision = 19, scale = 2)
    private BigDecimal approvedAmount;

    @Column(length = 64)
    private String priorAuthRef;

    @Enumerated(EnumType.STRING)
    @Column(nullable = false, length = 20)
    private LineStatus status = LineStatus.PENDING;

    @ElementCollection(fetch = FetchType.LAZY)
    @CollectionTable(
            name = "claim_line_adjustments",
            joinColumns = @JoinColumn(name = "claim_line_id")
    )
    private List<LineAdjustment> adjustments = new ArrayList<>();

    public ClaimLine(
            int lineNumber,
            String procedureCode,
            String diagnosisCode,
            LocalDate serviceDate,
            int units,
            BigDecimal billedAmount
    ) {
        this.lineNumber = lineNumber;
        this.procedureCode = procedureCode;
        this.diagnosisCode = diagnosisCode;
        this.serviceDate = serviceDate;
        this.units = units;
        this.billedAmount = money(billedAmount);
        this.status = LineStatus.PENDING;
    }

    /** Call after adjudication sets approvedAmount. */
    public void refreshStatusFromAmounts() {
        if (status == LineStatus.PENDING && approvedAmount == null) {
            return;
        }
        BigDecimal approved = zeroIfNull(approvedAmount);
        if (approved.compareTo(BigDecimal.ZERO) == 0) {
            status = LineStatus.DENIED;
        } else if (approved.compareTo(billedAmount) < 0) {
            status = LineStatus.REDUCED;
        } else {
            status = LineStatus.APPROVED;
        }
    }

    public void clearAdjudication() {
        approvedAmount = null;
        status = LineStatus.PENDING;
        adjustments.clear();
    }

    public void addAdjustment(LineAdjustment adjustment) {
        adjustments.add(adjustment);
    }

    public BigDecimal approvedAmountOrZero() {
        return zeroIfNull(approvedAmount);
    }

    private static BigDecimal money(BigDecimal value) {
        return value.setScale(2, RoundingMode.HALF_UP);
    }

    private static BigDecimal zeroIfNull(BigDecimal value) {
        return value == null ? BigDecimal.ZERO.setScale(2) : value;
    }

    void setClaim(Claim claim) {
        this.claim = claim;
    }
}
```

**Interview talking points:** status is derived from money; `clearAdjudication()` supports re-adjudication later.

