## 4. `Claim` entity (aggregate root)

Owns lines (`cascade = ALL`, `orphanRemoval = true`). Totals and outcome are recomputed, not set ad hoc in controllers.

```java
package com.realfast.claims.model;

import jakarta.persistence.*;
import lombok.AccessLevel;
import lombok.Getter;
import lombok.NoArgsConstructor;
import lombok.Setter;

import java.math.BigDecimal;
import java.math.RoundingMode;
import java.time.Instant;
import java.time.LocalDate;
import java.util.ArrayList;
import java.util.List;
import java.util.UUID;

@Entity
@Table(name = "claims")
@Getter
@Setter
@NoArgsConstructor(access = AccessLevel.PROTECTED)
public class Claim {

    @Id
    @GeneratedValue(strategy = GenerationType.UUID)
    private UUID id;

    @Column(nullable = false, unique = true, length = 40)
    private String claimNumber;

    @Column(nullable = false, length = 64)
    private String memberId;

    @Column(nullable = false, length = 64)
    private String providerId;

    @Column(nullable = false, length = 64)
    private String planId;

    @Enumerated(EnumType.STRING)
    @Column(nullable = false, length = 20)
    private ClaimStatus status = ClaimStatus.SUBMITTED;

    @Enumerated(EnumType.STRING)
    @Column(length = 20)
    private ClaimOutcome outcome;

    @Column(nullable = false)
    private LocalDate serviceFrom;

    @Column(nullable = false)
    private LocalDate serviceTo;

    @Column(nullable = false, precision = 19, scale = 2)
    private BigDecimal totalBilled = BigDecimal.ZERO.setScale(2);

    @Column(nullable = false, precision = 19, scale = 2)
    private BigDecimal totalApproved = BigDecimal.ZERO.setScale(2);

    @Column(nullable = false)
    private Instant submittedAt;

    private Instant adjudicatedAt;

    @OneToMany(
            mappedBy = "claim",
            cascade = CascadeType.ALL,
            orphanRemoval = true
    )
    @OrderBy("lineNumber ASC")
    private List<ClaimLine> lines = new ArrayList<>();

    public Claim(
            String claimNumber,
            String memberId,
            String providerId,
            String planId,
            LocalDate serviceFrom,
            LocalDate serviceTo
    ) {
        this.claimNumber = claimNumber;
        this.memberId = memberId;
        this.providerId = providerId;
        this.planId = planId;
        this.serviceFrom = serviceFrom;
        this.serviceTo = serviceTo;
        this.status = ClaimStatus.SUBMITTED;
        this.submittedAt = Instant.now();
    }

    public ClaimLine addLine(ClaimLine line) {
        line.setClaim(this);
        lines.add(line);
        recalculateTotals();
        return line;
    }

    public void recalculateTotals() {
        totalBilled = lines.stream()
                .map(ClaimLine::getBilledAmount)
                .reduce(BigDecimal.ZERO.setScale(2), this::addMoney);
        totalApproved = lines.stream()
                .map(ClaimLine::approvedAmountOrZero)
                .reduce(BigDecimal.ZERO.setScale(2), this::addMoney);
    }

    /**
     * Call after all lines are adjudicated (status != PENDING).
     * Sets outcome; does not change claim status — Adjudicator/service does that.
     */
    public ClaimOutcome deriveOutcome() {
        if (lines.isEmpty()) {
            outcome = ClaimOutcome.DENIED;
            return outcome;
        }
        boolean anyApproved = false;
        boolean anyDenied = false;
        for (ClaimLine line : lines) {
            switch (line.getStatus()) {
                case APPROVED, REDUCED -> anyApproved = true;
                case DENIED -> anyDenied = true;
                case PENDING -> throw new IllegalStateException(
                        "Cannot derive outcome while line " + line.getLineNumber() + " is PENDING");
            }
        }
        if (anyApproved && !anyDenied) {
            outcome = ClaimOutcome.APPROVED;
        } else if (anyDenied && !anyApproved) {
            outcome = ClaimOutcome.DENIED;
        } else {
            outcome = ClaimOutcome.PARTIAL;
        }
        return outcome;
    }

    public void markAdjudicated() {
        if (status != ClaimStatus.SUBMITTED && status != ClaimStatus.ADJUDICATED) {
            throw new IllegalStateException("Unexpected claim status: " + status);
        }
        deriveOutcome();
        recalculateTotals();
        status = ClaimStatus.ADJUDICATED;
        adjudicatedAt = Instant.now();
    }

    public boolean isAdjudicated() {
        return status == ClaimStatus.ADJUDICATED;
    }

    private BigDecimal addMoney(BigDecimal left, BigDecimal right) {
        return left.add(right).setScale(2, RoundingMode.HALF_UP);
    }
}
```

**JPA relationships summary**

| From | To | Mapping |
|------|-----|---------|
| `Claim` | `ClaimLine` | `@OneToMany(mappedBy="claim", cascade=ALL, orphanRemoval=true)` |
| `ClaimLine` | `Claim` | `@ManyToOne` + `setClaim` from `addLine` |
| `ClaimLine` | `LineAdjustment` | `@ElementCollection` + `@Embeddable` |

