```java
package com.realfast.claims.model;

import jakarta.persistence.*;
import lombok.AccessLevel;
import lombok.Getter;
import lombok.NoArgsConstructor;
import lombok.Setter;

import java.math.BigDecimal;
import java.time.LocalDate;
import java.util.ArrayList;
import java.util.List;
import java.util.UUID;

@Entity
@Table(name = "claim_lines")
@Getter
@Setter
@NoArgsConstructor
public class ClaimLine {

    @Id
    @GeneratedValue(strategy = GenerationType.UUID)
    private UUID id;

    @ManyToOne(fetch = FetchType.LAZY, optional = false)
    @JoinColumn(name = "claim_id", nullable = false)
    @Setter(AccessLevel.PACKAGE)
    private Claim claim;

    @Column(nullable = false)
    private int lineNumber;

    @Column(nullable = false, length = 16)
    private String procedureCode;

    @Column(length = 16)
    private String diagnosisCode;

    @Column(nullable = false)
    private LocalDate serviceDate;

    @Column(nullable = false)
    private int units = 1;

  /** Optional; used by auth rules in adjudication. */
    @Column(length = 64)
    private String priorAuthRef;

    @Column(nullable = false, precision = 12, scale = 2)
    private BigDecimal billedAmount;

    @Column(precision = 12, scale = 2)
    private BigDecimal approvedAmount;

    @Enumerated(EnumType.STRING)
    @Column(nullable = false, length = 16)
    private LineStatus status = LineStatus.PENDING;

    @ElementCollection
    @CollectionTable(name = "line_adjustments", joinColumns = @JoinColumn(name = "claim_line_id"))
    private List<LineAdjustment> adjustments = new ArrayList<>();

    public ClaimLine(int lineNumber, String procedureCode, LocalDate serviceDate, BigDecimal billedAmount) {
        this.lineNumber = lineNumber;
        this.procedureCode = procedureCode;
        this.serviceDate = serviceDate;
        this.billedAmount = billedAmount;
    }

    public void clearAdjudication() {
        this.approvedAmount = null;
        this.status = LineStatus.PENDING;
        this.adjustments.clear();
    }

    public void addAdjustment(LineAdjustment adjustment) {
        this.adjustments.add(adjustment);
    }

    /** Sets approved amount and derives line status from billed vs approved. */
    public void applyApprovedAmount(BigDecimal approved) {
        this.approvedAmount = approved;
        this.status = resolveStatus(this.billedAmount, approved);
    }

    static LineStatus resolveStatus(BigDecimal billed, BigDecimal approved) {
        if (approved.compareTo(BigDecimal.ZERO) == 0) {
            return LineStatus.DENIED;
        }
        if (approved.compareTo(billed) < 0) {
            return LineStatus.REDUCED;
        }
        return LineStatus.APPROVED;
    }
}
```

**Notes:** `billedAmount` is required at submit; `approvedAmount` stays null until adjudication. Status is derived from money so you don't drift out of sync.

