## Step 4 — `Claim` (aggregate root)

```java
package com.realfast.claims.model;

import jakarta.persistence.*;
import lombok.Getter;
import lombok.NoArgsConstructor;
import lombok.Setter;

import java.math.BigDecimal;
import java.time.Instant;
import java.time.LocalDate;
import java.util.ArrayList;
import java.util.List;
import java.util.UUID;

@Entity
@Table(name = "claims")
@Getter
@Setter
@NoArgsConstructor
public class Claim {

    @Id
    @GeneratedValue(strategy = GenerationType.UUID)
    private UUID id;

    @Column(nullable = false, unique = true, length = 32)
    private String claimNumber;

    @Column(nullable = false, length = 64)
    private String memberId;

    @Column(nullable = false, length = 64)
    private String providerId;

    @Column(nullable = false, length = 64)
    private String planId;

    @Enumerated(EnumType.STRING)
    @Column(nullable = false, length = 16)
    private ClaimStatus status = ClaimStatus.SUBMITTED;

    @Enumerated(EnumType.STRING)
    @Column(length = 16)
    private ClaimOutcome outcome;

    private LocalDate serviceFrom;
    private LocalDate serviceTo;

    @Column(nullable = false)
    private Instant submittedAt;

    private Instant adjudicatedAt;

    @Column(nullable = false, precision = 14, scale = 2)
    private BigDecimal totalBilled = BigDecimal.ZERO;

    @Column(nullable = false, precision = 14, scale = 2)
    private BigDecimal totalApproved = BigDecimal.ZERO;

    @OneToMany(mappedBy = "claim", cascade = CascadeType.ALL, orphanRemoval = true)
    @OrderBy("lineNumber ASC")
    private List<ClaimLine> lines = new ArrayList<>();

    public Claim(String claimNumber, String memberId, String providerId, String planId) {
        this.claimNumber = claimNumber;
        this.memberId = memberId;
        this.providerId = providerId;
        this.planId = planId;
        this.submittedAt = Instant.now();
    }

    public void addLine(ClaimLine line) {
        lines.add(line);
        line.setClaim(this);
    }

    public void assertSubmitted() {
        if (status != ClaimStatus.SUBMITTED) {
            throw new IllegalStateException("Claim must be SUBMITTED, was: " + status);
        }
    }

    public void recalculateTotals() {
        this.totalBilled = lines.stream()
                .map(ClaimLine::getBilledAmount)
                .reduce(BigDecimal.ZERO, BigDecimal::add);

        this.totalApproved = lines.stream()
                .map(line -> line.getApprovedAmount() != null ? line.getApprovedAmount() : BigDecimal.ZERO)
                .reduce(BigDecimal.ZERO, BigDecimal::add);
    }

    /**
     * All lines must have a final line status (not PENDING).
     */
    public ClaimOutcome deriveOutcome() {
        if (lines.isEmpty()) {
            return ClaimOutcome.DENIED;
        }
        if (lines.stream().anyMatch(line -> line.getStatus() == LineStatus.PENDING)) {
            throw new IllegalStateException("Cannot derive outcome while lines are PENDING");
        }
        boolean allDenied = lines.stream().allMatch(line -> line.getStatus() == LineStatus.DENIED);
        boolean allApproved = lines.stream().allMatch(line -> line.getStatus() == LineStatus.APPROVED);
        if (allDenied) {
            return ClaimOutcome.DENIED;
        }
        if (allApproved) {
            return ClaimOutcome.APPROVED;
        }
        return ClaimOutcome.PARTIAL;
    }

    /** Call after all lines are adjudicated. */
    public void markAdjudicated() {
        recalculateTotals();
        this.outcome = deriveOutcome();
        this.status = ClaimStatus.ADJUDICATED;
        this.adjudicatedAt = Instant.now();
    }
}
```

**Aggregate rules:** Only `Claim.addLine()` wires the parent; `cascade = ALL` + `orphanRemoval = true` keeps persistence aligned with the aggregate.

