package com.realfast.claims.policy;

import java.math.BigDecimal;
import lombok.Getter;

/**
 * Whether a procedure is covered under a plan and the maximum payable amount per line.
 */
@Getter
public class CoverageRule {

    private final String procedureCode;
    private final boolean covered;
    private final BigDecimal maxApprovedAmount;

    private CoverageRule(String procedureCode, boolean covered, BigDecimal maxApprovedAmount) {
        this.procedureCode = procedureCode;
        this.covered = covered;
        this.maxApprovedAmount = maxApprovedAmount;
    }

    public static CoverageRule covered(String procedureCode, BigDecimal maxApprovedAmount) {
        return new CoverageRule(procedureCode, true, maxApprovedAmount);
    }

    public static CoverageRule notCovered(String procedureCode) {
        return new CoverageRule(procedureCode, false, BigDecimal.ZERO);
    }
}

package com.realfast.claims.policy;

import java.util.HashMap;
import java.util.Map;
import java.util.Optional;

/**
 * Plan-level coverage: which procedure codes are covered and their payment caps.
 */
public class Policy {

    private final String planId;
    private final Map<String, CoverageRule> rulesByProcedure;

    public Policy(String planId, Map<String, CoverageRule> rulesByProcedure) {
        this.planId = planId;
        this.rulesByProcedure = Map.copyOf(rulesByProcedure);
    }

    public String getPlanId() {
        return planId;
    }

    public Optional<CoverageRule> ruleFor(String procedureCode) {
        return Optional.ofNullable(rulesByProcedure.get(normalize(procedureCode)));
    }

    private static String normalize(String procedureCode) {
        return procedureCode == null ? "" : procedureCode.trim().toLowerCase();
    }

    public static Builder builder(String planId) {
        return new Builder(planId);
    }

    public static final class Builder {
        private final String planId;
        private final Map<String, CoverageRule> rules = new HashMap<>();

        private Builder(String planId) {
            this.planId = planId;
        }

        public Builder add(CoverageRule rule) {
            rules.put(normalize(rule.getProcedureCode()), rule);
            return this;
        }

        public Policy build() {
            return new Policy(planId, rules);
        }

        private static String normalize(String procedureCode) {
            return procedureCode == null ? "" : procedureCode.trim().toLowerCase();
        }
    }
}

package com.realfast.claims.policy;

import java.math.BigDecimal;
import java.util.Map;
import java.util.concurrent.ConcurrentHashMap;
import org.springframework.stereotype.Component;

/**
 * In-memory plan policies for the MVP (replace with DB/config later).
 */
@Component
public class PolicyCatalog {

    private final Map<String, Policy> policies = new ConcurrentHashMap<>();

    public PolicyCatalog() {
        registerDefaultPolicies();
    }

    public Policy requirePolicy(String planId) {
        Policy policy = policies.get(planId);
        if (policy == null) {
            throw new IllegalArgumentException("Unknown plan: " + planId);
        }
        return policy;
    }

    private void registerDefaultPolicies() {
        Policy basic = Policy.builder("PLAN-BASIC")
                .add(CoverageRule.covered("99213", new BigDecimal("120.00")))
                .add(CoverageRule.covered("99214", new BigDecimal("180.00")))
                .add(CoverageRule.covered("office-visit", new BigDecimal("100.00")))
                .add(CoverageRule.notCovered("experimental"))
                .build();
        policies.put(basic.getPlanId(), basic);
    }
}

package com.realfast.claims;

import com.realfast.claims.model.Claim;
import com.realfast.claims.model.ClaimLine;
import com.realfast.claims.model.LineAdjustment;
import com.realfast.claims.model.LineStatus;
import com.realfast.claims.policy.CoverageRule;
import com.realfast.claims.policy.Policy;
import com.realfast.claims.policy.PolicyCatalog;
import java.math.BigDecimal;
import java.util.ArrayList;
import java.util.List;
import org.springframework.stereotype.Service;

/**
 * Runs coverage rules on each line, then rolls up claim totals and outcome.
 */
@Service
public class Adjudicator {

    private final PolicyCatalog policyCatalog;

    public Adjudicator(PolicyCatalog policyCatalog) {
        this.policyCatalog = policyCatalog;
    }

    public void adjudicate(Claim claim) {
        claim.assertSubmitted();
        Policy policy = policyCatalog.requirePolicy(claim.getPlanId());

        for (ClaimLine line : claim.getLines()) {
            adjudicateLine(line, policy);
        }

        claim.finalizeAdjudication();
    }

    private void adjudicateLine(ClaimLine line, Policy policy) {
        line.clearAdjudication();

        BigDecimal billed = line.getBilledAmount();
        var ruleOptional = policy.ruleFor(line.getProcedureCode());

        if (ruleOptional.isEmpty()) {
            deny(line, "NOT_ON_PLAN", "Procedure is not listed on this plan");
            return;
        }

        CoverageRule rule = ruleOptional.get();
        if (!rule.isCovered()) {
            deny(line, "NOT_COVERED", "Procedure is excluded from coverage");
            return;
        }

        BigDecimal cap = rule.getMaxApprovedAmount();
        BigDecimal approved = billed.min(cap);

        List<LineAdjustment> adjustments = new ArrayList<>();
        if (approved.compareTo(billed) < 0) {
            adjustments.add(LineAdjustment.reduction(
                    "CONTRACTUAL",
                    "Approved amount is less than the billed amount",
                    billed.subtract(approved)));
        }

        LineStatus status = ClaimLine.statusFromAmounts(billed, approved);
        line.applyAdjudication(approved, status, adjustments);
    }

    private void deny(ClaimLine line, String code, String description) {
        line.applyAdjudication(
                BigDecimal.ZERO,
                LineStatus.DENIED,
                List.of(LineAdjustment.denial(code, description)));
    }
}

package com.realfast.claims;

import static org.assertj.core.api.Assertions.assertThat;

import com.realfast.claims.model.Claim;
import com.realfast.claims.model.ClaimLine;
import com.realfast.claims.model.ClaimOutcome;
import com.realfast.claims.model.ClaimStatus;
import com.realfast.claims.model.LineStatus;
import com.realfast.claims.policy.PolicyCatalog;
import java.math.BigDecimal;
import java.time.LocalDate;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class AdjudicatorTest {

    private Adjudicator adjudicator;

    @BeforeEach
    void setUp() {
        adjudicator = new Adjudicator(new PolicyCatalog());
    }

    @Test
    void fullyApprovesWhenBilledAtOrBelowCap() {
        Claim claim = claimWithLine("99213", "150.00");

        adjudicator.adjudicate(claim);

        var line = claim.getLines().getFirst();
        assertThat(line.getStatus()).isEqualTo(LineStatus.APPROVED);
        assertThat(line.getApprovedAmount()).isEqualByComparingTo("120.00");
        assertThat(line.getAdjustments()).isEmpty();
        assertThat(claim.getOutcome()).isEqualTo(ClaimOutcome.PARTIAL);
    }

    @Test
    void reducesWhenBilledExceedsCap() {
        Claim claim = claimWithLine("office-visit", "150.00");

        adjudicator.adjudicate(claim);

        var line = claim.getLines().getFirst();
        assertThat(line.getStatus()).isEqualTo(LineStatus.REDUCED);
        assertThat(line.getApprovedAmount()).isEqualByComparingTo("100.00");
        assertThat(line.getAdjustments()).hasSize(1);
        assertThat(line.getAdjustments().getFirst().getCode()).isEqualTo("CONTRACTUAL");
    }

    @Test
    void deniesExcludedProcedure() {
        Claim claim = claimWithLine("experimental", "500.00");

        adjudicator.adjudicate(claim);

        var line = claim.getLines().getFirst();
        assertThat(line.getStatus()).isEqualTo(LineStatus.DENIED);
        assertThat(line.getApprovedAmount()).isEqualByComparingTo("0");
        assertThat(claim.getOutcome()).isEqualTo(ClaimOutcome.DENIED);
    }

    @Test
    void partialClaimWhenLinesDiffer() {
        Claim claim = newClaim();
        claim.addLine(line(1, "99213", "80.00"));
        claim.addLine(line(2, "experimental", "200.00"));

        adjudicator.adjudicate(claim);

        assertThat(claim.getStatus()).isEqualTo(ClaimStatus.ADJUDICATED);
        assertThat(claim.getOutcome()).isEqualTo(ClaimOutcome.PARTIAL);
        assertThat(claim.getTotalBilled()).isEqualByComparingTo("280.00");
        assertThat(claim.getTotalApproved()).isEqualByComparingTo("80.00");
    }

    private static Claim claimWithLine(String procedureCode, String billed) {
        Claim claim = newClaim();
        claim.addLine(line(1, procedureCode, billed));
        return claim;
    }

    private static Claim newClaim() {
        return new Claim("M-1", "P-1", "PLAN-BASIC", LocalDate.of(2026, 5, 1), LocalDate.of(2026, 5, 1));
    }

    private static ClaimLine line(int lineNumber, String procedureCode, String billed) {
        return new ClaimLine(
                lineNumber,
                procedureCode,
                "dx",
                LocalDate.of(2026, 5, 1),
                1,
                new BigDecimal(billed));
    }
}

