package com.realfast.claims.web.dto;

import com.realfast.claims.model.Claim;
import com.realfast.claims.model.ClaimLine;
import com.realfast.claims.model.LineAdjustment;
import org.springframework.stereotype.Component;

@Component
public class ClaimMapper {

    public Claim toClaim(SubmitClaimRequest request) {
        return submitBuilder(request).build();
    }

    public ClaimResponse toResponse(Claim claim) {
        return responseBuilder(claim).build();
    }

    public SubmitClaimBuilder submitBuilder(SubmitClaimRequest request) {
        return new SubmitClaimBuilder(request);
    }

    public ClaimResponseBuilder responseBuilder(Claim claim) {
        return new ClaimResponseBuilder(claim);
    }

    public final class SubmitClaimBuilder {

        private final SubmitClaimRequest request;

        private SubmitClaimBuilder(SubmitClaimRequest request) {
            this.request = request;
        }

        public Claim build() {
            Claim claim = new Claim(
                    request.memberId(),
                    request.providerId(),
                    request.planId(),
                    request.serviceFrom(),
                    request.serviceTo());
            request.lines().forEach(lineRequest -> claim.addLine(toLine(lineRequest)));
            return claim;
        }

        private ClaimLine toLine(SubmitClaimLineRequest lineRequest) {
            return new ClaimLine(
                    lineRequest.lineNumber(),
                    lineRequest.procedureCode(),
                    lineRequest.diagnosisCode(),
                    lineRequest.serviceDate(),
                    lineRequest.units(),
                    lineRequest.billedAmount());
        }
    }

    public final class ClaimResponseBuilder {

        private final Claim claim;

        private ClaimResponseBuilder(Claim claim) {
            this.claim = claim;
        }

        public ClaimResponse build() {
            return new ClaimResponse(
                    claim.getId(),
                    claim.getClaimNumber(),
                    claim.getMemberId(),
                    claim.getProviderId(),
                    claim.getPlanId(),
                    claim.getServiceFrom(),
                    claim.getServiceTo(),
                    claim.getStatus(),
                    claim.getOutcome(),
                    claim.getSubmittedAt(),
                    claim.getAdjudicatedAt(),
                    claim.getTotalBilled(),
                    claim.getTotalApproved(),
                    claim.getLines().stream().map(this::toLineResponse).toList());
        }

        private ClaimLineResponse toLineResponse(ClaimLine line) {
            return new ClaimLineResponse(
                    line.getId(),
                    line.getLineNumber(),
                    line.getProcedureCode(),
                    line.getDiagnosisCode(),
                    line.getServiceDate(),
                    line.getUnits(),
                    line.getBilledAmount(),
                    line.getApprovedAmount(),
                    line.getStatus(),
                    line.getAdjustments().stream().map(this::toAdjustmentResponse).toList());
        }

        private LineAdjustmentResponse toAdjustmentResponse(LineAdjustment adjustment) {
            return new LineAdjustmentResponse(
                    adjustment.getCode(),
                    adjustment.getType(),
                    adjustment.getDescription(),
                    adjustment.getAmount());
        }
    }
}

