                request.lineNumber(),
                request.procedureCode(),
                request.diagnosisCode(),
                request.serviceDate(),
                request.units(),
                request.billedAmount());
    }

    public static ClaimResponse toResponse(Claim claim) {
        return ClaimResponse.builder()
                .id(claim.getId())
                .claimNumber(claim.getClaimNumber())
                .memberId(claim.getMemberId())
