package com.realfast.claims.policy;

import java.math.BigDecimal;
import lombok.Builder;
import lombok.Getter;

/**
 * Whether a procedure is covered under a plan and the maximum payable amount per line.
 */
@Getter
@Builder
public class CoverageRule {

    private final String procedureCode;
    private final boolean covered;
    private final BigDecimal maxApprovedAmount;

    public static CoverageRule covered(String procedureCode, BigDecimal maxApprovedAmount) {
        return CoverageRule.builder()
                .procedureCode(procedureCode)
                .covered(true)
                .maxApprovedAmount(maxApprovedAmount)
                .build();
    }

    public static CoverageRule notCovered(String procedureCode) {
        return CoverageRule.builder()
                .procedureCode(procedureCode)
                .covered(false)
                .maxApprovedAmount(BigDecimal.ZERO)
                .build();
    }
}

package com.realfast.claims.policy;

import java.util.List;
import java.util.Map;
import java.util.Optional;
import java.util.stream.Collectors;
import lombok.Builder;
import lombok.Getter;
import lombok.Singular;

/**
 * Plan-level coverage: which procedure codes are covered and their payment caps.
 */
@Getter
public class Policy {

    private final String planId;
    private final Map<String, CoverageRule> rulesByProcedure;

    @Builder
    private Policy(String planId, @Singular List<CoverageRule> rules) {
        this.planId = planId;
        this.rulesByProcedure = rules.stream()
                .collect(Collectors.toUnmodifiableMap(rule -> normalize(rule.getProcedureCode()), rule -> rule));
    }

    public Optional<CoverageRule> ruleFor(String procedureCode) {
        return Optional.ofNullable(rulesByProcedure.get(normalize(procedureCode)));
    }

    static String normalize(String procedureCode) {
        return procedureCode == null ? "" : procedureCode.trim().toLowerCase();
    }
}

package com.realfast.claims.service;

import com.realfast.claims.exception.ClaimNotFoundException;
import com.realfast.claims.model.Claim;
import com.realfast.claims.model.ClaimLine;
import com.realfast.claims.model.ClaimStatus;
import com.realfast.claims.repository.ClaimRepository;
import com.realfast.claims.web.dto.ClaimMapper;
import com.realfast.claims.web.dto.ClaimResponse;
import com.realfast.claims.web.dto.SubmitClaimLineRequest;
import com.realfast.claims.web.dto.SubmitClaimRequest;
import java.util.List;
import java.util.UUID;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

@Service
@Transactional
public class ClaimService {

    private final ClaimRepository claimRepository;
    private final Adjudicator adjudicator;

    public ClaimService(ClaimRepository claimRepository, Adjudicator adjudicator) {
        this.claimRepository = claimRepository;
        this.adjudicator = adjudicator;
    }

    public ClaimResponse submit(SubmitClaimRequest request) {
        Claim claim = buildClaim(request);
        Claim saved = claimRepository.save(claim);
        return toResponse(saved);
    }

    public ClaimResponse adjudicate(UUID id) {
        Claim claim = loadClaim(id);
        adjudicator.adjudicate(claim);
        Claim saved = claimRepository.save(claim);
        return toResponse(saved);
    }

    @Transactional(readOnly = true)
    public ClaimResponse getById(UUID id) {
        return toResponse(loadClaim(id));
    }

    @Transactional(readOnly = true)
    public List<ClaimResponse> getByStatus(ClaimStatus status) {
        return claimRepository.findByStatus(status).stream()
                .map(this::toResponse)
                .toList();
    }

    private Claim buildClaim(SubmitClaimRequest request) {
        Claim claim = ClaimMapper.toClaim(request);
        request.lines().forEach(lineRequest -> claim.addLine(toLine(lineRequest)));
        claim.recalculateTotals();
        return claim;
    }

    private ClaimLine toLine(SubmitClaimLineRequest lineRequest) {
        return ClaimMapper.toLine(lineRequest);
    }

    private ClaimResponse toResponse(Claim claim) {
        return ClaimMapper.toResponse(claim);
    }

    private Claim loadClaim(UUID id) {
        return claimRepository.findById(id).orElseThrow(() -> new ClaimNotFoundException(id));
    }
}

package com.realfast.claims.controller;

import com.realfast.claims.model.ClaimStatus;
import com.realfast.claims.service.ClaimService;
import com.realfast.claims.web.dto.ClaimResponse;
import com.realfast.claims.web.dto.SubmitClaimRequest;
import jakarta.validation.Valid;
import java.util.List;
import java.util.UUID;
import lombok.RequiredArgsConstructor;
import org.springframework.http.HttpStatus;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.PathVariable;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.RequestBody;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RequestParam;
import org.springframework.web.bind.annotation.ResponseStatus;
import org.springframework.web.bind.annotation.RestController;

@RestController
@RequestMapping("/api/v1/claims")
@RequiredArgsConstructor
public class ClaimController {

    private final ClaimService claimService;

    @PostMapping
    @ResponseStatus(HttpStatus.CREATED)
    public ClaimResponse submit(@Valid @RequestBody SubmitClaimRequest request) {
        return claimService.submit(request);
    }

    @PostMapping("/{id}/adjudicate")
    public ClaimResponse adjudicate(@PathVariable UUID id) {
        return claimService.adjudicate(id);
    }

    @GetMapping("/{id}")
    public ClaimResponse getById(@PathVariable UUID id) {
        return claimService.getById(id);
    }

    @GetMapping
    public List<ClaimResponse> listByStatus(@RequestParam ClaimStatus status) {
        return claimService.getByStatus(status);
    }
}
